let pasos = 3;
robot.move(pasos);

const direccion = 'derecha';
robot.turn(direccion);

function reactivar(generador) {
  robot.move(generador.distancia);
  robot.activate();
}

reactivar(generador1);
reactivar(generador2);

const maquinaA = {
  potencia: 80,
  estado: 'inactivo',
  tipo: 'incubadora'
};

console.log(maquinaA.tipo);
maquinaA.estado = 'activo';

function arrancar(maquina, callback) {
  maquina.iniciar();
  callback();
}

arrancar(maquinaA, function() {
  robot.activate();
});
